{
  "mode": "io",
  "tests": [
    {
      "name": "empty_input",
      "input": "",
      "output": "No data provided",
      "notes": "Tests the behavior when no input is given."
    },
    {
      "name": "single_character_input",
      "input": "a",
      "output": "Invalid input",
      "notes": "Tests the handling of minimal input length."
    },
    {
      "name": "long_input",
      "input": "a" * 1000,
      "output": "Input too long",
      "notes": "Tests the upper limit of input length."
    },
    {
      "name": "special_characters",
      "input": "!@#$%^&*()",
      "output": "Invalid characters",
      "notes": "Tests the handling of special characters in input."
    },
    {
      "name": "valid_input",
      "input": "valid_input_example",
      "output": "Input accepted",
      "notes": "Tests a valid input scenario."
    },
    {
      "name": "whitespace_input",
      "input": "   ",
      "output": "No data provided",
      "notes": "Tests the handling of whitespace-only input."
    },
    {
      "name": "numeric_input",
      "input": "123456",
      "output": "Invalid input",
      "notes": "Tests the handling of numeric input."
    },
    {
      "name": "mixed_input",
      "input": "valid123!@#",
      "output": "Invalid input",
      "notes": "Tests the handling of mixed valid and invalid characters."
    }
  ],
  "assumptions": "Input must be a non-empty string with specific character constraints.",
  "notes": "Ensure to validate input thoroughly against the defined constraints."
}
